    """Given an integer. output a tuple that has the number of divisible-by-two and odd-valued digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    even_count = 0
    odd_count = 0
    for i in str(abs(value)):
