def common(first: list, b: list):
    """Output ascending distinct common elements for two lists.
    >>> common([1, 4, 3, 34, 653, 2, 5], [5, 7, 1, 5, 9, 653, 121])
    [1, 5, 653]
    >>> common([5, 3, 2, 8], [3, 2])
    [2, 3]

    """
    ret = set()
    for e1 in first:
        for e2 in b:
            if e1 == e2:
                ret.add(e1)
    return sorted(list(ret))

